let keywords = [];
try { keywords = $('Sheets — Keywords lesen').all().map(i => i.json); } catch(e) {}

let analyse = [];
try { analyse = $('Sheets — Semantische Analyse lesen').all().map(i => i.json); } catch(e) {}

let insights = [];
try { insights = $('Sheets — User Insights lesen').all().map(i => i.json); } catch(e) {}

const spreadsheetId = $('WF5 Variablen').first().json.spreadsheet_id;

const getField = (obj, names) => {
  for (const name of names) {
    for (const key of Object.keys(obj)) {
      if (key.toLowerCase() === name.toLowerCase()) return obj[key];
    }
  }
  return '';
};

// Normalize analyse entries
const normAnalyse = analyse.map(a => {
  const kategorie = getField(a, ['kategorie', 'Kategorie', 'category']).toString().toLowerCase();
  const analyseTyp = getField(a, ['analyse_typ', 'Analyse_Typ', 'type', 'typ']).toString().toLowerCase();
  return {
    kategorie,
    analyse_typ: analyseTyp,
    keyword_oder_thema: getField(a, ['keyword_oder_thema', 'Keyword_oder_Thema', 'keyword', 'thema', 'Thema', 'topic']),
    details: getField(a, ['details', 'Details', 'beschreibung', 'Beschreibung']),
    suchintention: getField(a, ['suchintention', 'Suchintention', 'intent'])
  };
});

// Category matching
const isCommodity = (a) => 
  a.analyse_typ === 'commodity' || 
  a.kategorie.includes('commodity') || 
  a.kategorie.includes('pflicht') || 
  a.kategorie.includes('basis') || 
  a.kategorie.includes('kern');

const isLuecke = (a) => 
  a.analyse_typ === 'luecke' || 
  a.kategorie.includes('luecke') || 
  a.kategorie.includes('l\u00fccke') || 
  a.kategorie.includes('gap');

const isDifferenzierung = (a) => 
  a.analyse_typ === 'differenzierung' || 
  a.kategorie.includes('differenzierung');

let commodityTopics = normAnalyse.filter(isCommodity);
const lueckeTopics = normAnalyse.filter(isLuecke);
const diffTopics = normAnalyse.filter(isDifferenzierung);

// === FALLBACK: Wenn 0 Commodity-Themen, Keywords als Commodity verwenden ===
let fallbackUsed = false;
if (commodityTopics.length === 0) {
  fallbackUsed = true;
  // Nimm die Top-Keywords (nach Suchvolumen sortiert wenn vorhanden)
  const kwSorted = [...keywords].sort((a, b) => {
    const volA = Number(getField(a, ['suchvolumen', 'Suchvolumen', 'volume']) || 0);
    const volB = Number(getField(b, ['suchvolumen', 'Suchvolumen', 'volume']) || 0);
    return volB - volA;
  });
  // Top 10 Keywords als Commodity-Themen
  commodityTopics = kwSorted.slice(0, 10).map(k => ({
    kategorie: 'commodity (fallback)',
    analyse_typ: 'commodity',
    keyword_oder_thema: getField(k, ['keyword', 'Keyword', 'term']),
    details: 'Fallback: Aus Keywords generiert (keine Commodity-Themen in Analyse)',
    suchintention: getField(k, ['suchintention', 'Suchintention', 'intent'])
  }));
}

// Keywords
const normKeywords = keywords.map(k => ({
  keyword: getField(k, ['keyword', 'Keyword', 'term']),
  suchvolumen: Number(getField(k, ['suchvolumen', 'Suchvolumen', 'volume']) || 0),
  ausgewaehlt: getField(k, ['ausgewaehlt', 'Ausgewaehlt', 'selected', 'ausgew\u00e4hlt']).toString().toLowerCase()
}));
const selectedKeywords = normKeywords.filter(k => ['ja', 'true', 'x', '1'].includes(k.ausgewaehlt));
const finalKeywords = selectedKeywords.length > 0 ? selectedKeywords : normKeywords.slice(0, 10);

const uniqueAngles = insights.filter(i => {
  const ua = getField(i, ['unique_angle', 'Unique_Angle']).toString().toLowerCase();
  return ua === 'ja' || ua === 'true';
});
const expertInsights = insights.filter(i => {
  const q = getField(i, ['quelle', 'Quelle', 'source']).toString().toLowerCase();
  return q.includes('expert');
});
const userQuestions = insights.filter(i => {
  const t = getField(i, ['typ', 'Typ', 'type']).toString().toLowerCase();
  return t === 'frage' || t === 'question';
});

const allCategories = [...new Set(normAnalyse.map(a => a.kategorie))];
const allAnalyseTypen = [...new Set(normAnalyse.map(a => a.analyse_typ))];

return [{
  json: {
    spreadsheet_id: spreadsheetId,
    selected_keywords: JSON.stringify(finalKeywords),
    commodity_topics: JSON.stringify(commodityTopics),
    luecke_topics: JSON.stringify(lueckeTopics),
    diff_topics: JSON.stringify(diffTopics),
    unique_angles: JSON.stringify(uniqueAngles),
    expert_insights: JSON.stringify(expertInsights),
    user_questions: JSON.stringify(userQuestions),
    all_analyse: JSON.stringify(normAnalyse),
    keyword_count: finalKeywords.length,
    commodity_count: commodityTopics.length,
    luecke_count: lueckeTopics.length,
    diff_count: diffTopics.length,
    unique_count: uniqueAngles.length,
    expert_count: expertInsights.length,
    fallback_used: fallbackUsed ? 'ja' : 'nein',
    debug_all_categories: allCategories.join(' | '),
    debug_all_analyse_typen: allAnalyseTypen.join(' | '),
    debug_analyse_count: normAnalyse.length
  }
}];

const response = $input.first().json;
const spreadsheetId = $('WF5 Variablen').first().json.spreadsheet_id;

let content = '';
try {
  content = response.content?.[0]?.text || response.content || '';
} catch (e) {
  content = JSON.stringify(response);
}

let outline = [];
try {
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    outline = JSON.parse(jsonMatch[0]);
  } else {
    outline = JSON.parse(content);
  }
} catch (e) {
  outline = [{ position: 1, ebene: 'h1', ueberschrift: 'Parsing fehlgeschlagen', typ: 'hauptteil', basiert_auf: 'commodity', stichpunkte: content.slice(0, 500) }];
}

// Rule 1: Exactly ONE h1
let h1Found = false;
outline = outline.map(item => {
  if (item.ebene === 'h1') {
    if (!h1Found) {
      h1Found = true;
      return item;
    } else {
      return { ...item, ebene: 'h2' };
    }
  }
  return item;
});

// Rule 2: Validate basiert_auf values
const validBasis = ['commodity', 'luecke', 'unique_angle', 'expert_take'];
outline = outline.map(item => {
  if (!validBasis.includes(item.basiert_auf)) {
    item.basiert_auf = 'commodity';
  }
  return item;
});

// Rule 3: Enforce distribution limits
const byCat = {};
validBasis.forEach(cat => byCat[cat] = []);
outline.forEach(item => byCat[item.basiert_auf].push(item));

const limits = { commodity: 999, luecke: 3, unique_angle: 2, expert_take: 2 };
const selected = [];
for (const cat of validBasis) {
  const items = byCat[cat] || [];
  selected.push(...items.slice(0, limits[cat]));
}

selected.sort((a, b) => Number(a.position) - Number(b.position));

return selected.map((item, idx) => ({
  json: {
    position: idx + 1,
    ebene: item.ebene || 'h2',
    ueberschrift: item.ueberschrift || '',
    typ: item.typ || 'hauptteil',
    basiert_auf: item.basiert_auf || 'commodity',
    stichpunkte: item.stichpunkte || '',
    freigabe: 'nein',
    spreadsheet_id: spreadsheetId
  }
}));

const items = $input.all();
const spreadsheetId = items[0].json.spreadsheet_id;

const header = ['position', 'ebene', 'ueberschrift', 'typ', 'basiert_auf', 'stichpunkte', 'freigabe'];
const rows = items.map(item => [
  String(item.json.position || ''),
  item.json.ebene || '',
  item.json.ueberschrift || '',
  item.json.typ || '',
  item.json.basiert_auf || '',
  item.json.stichpunkte || '',
  item.json.freigabe || 'nein'
]);

return [{
  json: {
    spreadsheet_id: spreadsheetId,
    all_values: JSON.stringify({ values: [header, ...rows] }),
    row_count: rows.length
  }
}];

